{"code": "import re
import json

clinical_data = env['data_1']
mutation_data = env['data_2']

print(f"Clinical data length: {len(clinical_data)}")
print(f"Mutation data length: {len(mutation_data)}")

mutated_barcodes = {row['ParticipantBarcode'] for row in mutation_data}

histology_counts = {}
histology_mutated = {}

for row in clinical_data:
    desc = row.get('Patient_description', '')
    hist = row.get('histological_type', '')

    if not hist or hist.startswith('['):
        continue

    match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if match:
        barcode = match.group()

        if hist not in histology_counts:
            histology_counts[hist] = 0
            histology_mutated[hist] = 0

        histology_counts[hist] += 1
        if barcode in mutated_barcodes:
            histology_mutated[hist] += 1

results = []
for hist in histology_counts:
    if histology_counts[hist] > 0:
        pct = (histology_mutated[hist] / histology_counts[hist]) * 100
        results.append((hist, pct, histology_mutated[hist], histology_counts[hist]))

results.sort(key=lambda x: x[1], reverse=True)

print("Top 5 histological types by CDH1 mutation percentage:")
for r in results[:5]:
    print(f"{r[0]}: {r[1]:.2f}% ({r[2]}/{r[3]})")
"}

